import { useEffect, useState } from "react";
import api from "../api";

export default function GroupManagerModal({ open, onClose, onChanged }) {
    const [rows, setRows] = useState([]);
    const [loading, setLoading] = useState(true);
    const [editing, setEditing] = useState(null);
    const [form, setForm] = useState({ code: "", name: "", benefits: "", active: true });
    const [saving, setSaving] = useState(false);

    useEffect(() => {
        if (!open) return;
        load();
    }, [open]);

    async function load() {
        setLoading(true);
        try {
            const { data } = await api.get("/api/customer-groups", { params: { activeOnly: false } });
            setRows(Array.isArray(data) ? data : []);
        } catch (e) {
            console.error(e);
            setRows([]);
        } finally {
            setLoading(false);
        }
    }

    function openCreate() {
        setEditing(null);
        setForm({ code: "", name: "", benefits: "", active: true });
    }
    function openEdit(g) {
        setEditing(g);
        setForm({
            code: g.code || "",
            name: g.name || "",
            benefits: g.benefits || "",
            active: !!g.active,
        });
    }

    async function save(e) {
        e.preventDefault();
        setSaving(true);
        try {
            const payload = {
                code: form.code?.trim(),
                name: form.name?.trim(),
                benefits: form.benefits?.trim() || null,
                active: !!form.active,
            };
            if (editing) {
                await api.put(`/api/customer-groups/${editing.id}`, payload);
            } else {
                await api.post(`/api/customer-groups`, payload);
            }
            await load();
            onChanged?.(); // báo cho trang cha reload options
            openCreate(); // reset form
        } catch (err) {
            const msg = err?.response?.data?.message || err?.response?.data?.error || "Lưu nhóm thất bại";
            alert(msg);
        } finally {
            setSaving(false);
        }
    }

    async function removeRow(g) {
        if (!window.confirm(`Xoá nhóm "${g.name}"?`)) return;
        try {
            await api.delete(`/api/customer-groups/${g.id}`);
            await load();
            onChanged?.();
        } catch (err) {
            const msg = err?.response?.data?.message || err?.response?.data?.error || "Xoá nhóm thất bại";
            alert(msg);
        }
    }

    if (!open) return null;

    return (
        <div className="fixed inset-0 z-50 bg-black/40 grid place-items-center p-4">
            <div className="w-full max-w-5xl bg-white rounded-2xl shadow-xl border border-indigo-100">
                <div className="p-5 border-b flex items-center justify-between">
                    <div className="font-semibold">Quản lý nhóm khách hàng</div>
                    <button className="text-slate-500 hover:text-slate-700" onClick={onClose}>Đóng</button>
                </div>

                <div className="p-5 grid grid-cols-1 lg:grid-cols-3 gap-6">
                    {/* Danh sách nhóm */}
                    <div className="lg:col-span-2">
                        <div className="bg-white rounded-xl border border-indigo-100 overflow-hidden">
                            <div className="px-4 py-3 border-b flex items-center justify-between">
                                <div className="font-medium">Danh sách</div>
                                <button onClick={openCreate} className="px-3 py-1.5 rounded bg-indigo-600 text-white hover:bg-indigo-700">Thêm nhóm</button>
                            </div>
                            <div className="overflow-auto">
                                <table className="min-w-full text-sm">
                                    <thead className="bg-indigo-50 text-slate-600">
                                    <tr>
                                        <th className="px-3 py-2 text-left">Mã</th>
                                        <th className="px-3 py-2 text-left">Tên</th>
                                        <th className="px-3 py-2 text-left">Lợi ích</th>
                                        <th className="px-3 py-2 text-left">Trạng thái</th>
                                        <th className="px-3 py-2 text-right">Thao tác</th>
                                    </tr>
                                    </thead>
                                    <tbody className="divide-y">
                                    {loading ? (
                                        <tr><td className="px-4 py-6" colSpan={5}>Đang tải…</td></tr>
                                    ) : rows.length === 0 ? (
                                        <tr><td className="px-4 py-6" colSpan={5}>Chưa có nhóm</td></tr>
                                    ) : rows.map(g => (
                                        <tr key={g.id} className="hover:bg-indigo-50/40">
                                            <td className="px-3 py-2 font-medium">{g.code}</td>
                                            <td className="px-3 py-2">{g.name}</td>
                                            <td className="px-3 py-2">{g.benefits || "-"}</td>
                                            <td className="px-3 py-2">
                          <span className={"px-2 py-0.5 rounded-full text-xs " + (g.active ? "bg-emerald-100 text-emerald-700" : "bg-slate-200 text-slate-700")}>
                            {g.active ? "ACTIVE" : "INACTIVE"}
                          </span>
                                            </td>
                                            <td className="px-3 py-2 text-right">
                                                <div className="inline-flex gap-2">
                                                    <button onClick={() => openEdit(g)} className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100">Sửa</button>
                                                    <button onClick={() => removeRow(g)} className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100">Xoá</button>
                                                </div>
                                            </td>
                                        </tr>
                                    ))}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    </div>

                    {/* Form */}
                    <form onSubmit={save} className="bg-white rounded-xl border border-indigo-100 p-4 h-fit">
                        <div className="font-medium mb-3">{editing ? "Sửa nhóm" : "Thêm nhóm"}</div>
                        <div className="space-y-3">
                            <div>
                                <label className="text-sm text-slate-600">Mã nhóm</label>
                                <input
                                    required
                                    placeholder="VD: VIP, POTENTIAL, NORMAL…"
                                    value={form.code}
                                    onChange={(e) => setForm(f => ({ ...f, code: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Tên hiển thị</label>
                                <input
                                    required
                                    placeholder="VD: VIP / Tiềm năng / Thường…"
                                    value={form.name}
                                    onChange={(e) => setForm(f => ({ ...f, name: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Lợi ích / Ghi chú</label>
                                <textarea
                                    rows={5}
                                    placeholder="Ưu tiên hỗ trợ, chiết khấu, chăm sóc định kỳ…"
                                    value={form.benefits}
                                    onChange={(e) => setForm(f => ({ ...f, benefits: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>
                            <label className="inline-flex items-center gap-2 text-sm">
                                <input
                                    type="checkbox"
                                    checked={!!form.active}
                                    onChange={(e) => setForm(f => ({ ...f, active: e.target.checked }))}
                                />
                                Kích hoạt (cho phép chọn)
                            </label>

                            <div className="flex justify-end">
                                <button disabled={saving} className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700 disabled:opacity-50">
                                    {saving ? "Đang lưu…" : (editing ? "Cập nhật" : "Thêm")}
                                </button>
                            </div>
                        </div>
                    </form>
                </div>

                <div className="p-4 border-t text-xs text-slate-500">
                    * Mã nhóm sẽ được dùng làm giá trị lưu trong Khách hàng. Bạn có thể thêm mã hoàn toàn mới (VD: SME/ENTERPRISE) mà không cần sửa cấu trúc Customer.
                </div>
            </div>
        </div>
    );
}
